import React, { useState, useEffect } from 'react';
import { getProjects, createProject } from '../services/api';
import KanbanBoard from './KanbanBoard';

export default function Dashboard({ user, onLogout }){
  const [projects,setProjects]=useState([]);
  const [selected,setSelected]=useState(null);
  const [name,setName]=useState('');

  useEffect(()=>{ load(); },[])
  async function load(){
    const data = await getProjects();
    setProjects(data);
    if(data.length) setSelected(data[0]);
  }

  async function addProject(e){
    e.preventDefault();
    const p = await createProject({name,description:''});
    setProjects([p,...projects]);
    setName('');
  }

  return (
    <div className="app">
      <header>
        <h2>TaskMaster</h2>
        <div>
          <span>{user.username}</span>
          <button onClick={()=>{localStorage.clear(); onLogout();}}>Logout</button>
        </div>
      </header>
      <div className="main">
        <aside className="sidebar">
          <form onSubmit={addProject} className="card">
            <input placeholder="New project name" value={name} onChange={e=>setName(e.target.value)} />
            <button>Create</button>
          </form>
          <div className="projects card">
            {projects.map(p=> <div key={p.id} className={selected && selected.id===p.id? 'project selected':'project'} onClick={()=>setSelected(p)}>{p.name}</div>)}
          </div>
        </aside>
        <section className="content">
          {selected ? <KanbanBoard project={selected} /> : <div>Select a project</div>}
        </section>
      </div>
    </div>
  )
}
